1	import { existsSync, readFileSync } from "node:fs";
2	import { homedir } from "node:os";
3	import { basename, join, resolve } from "node:path";
4	import { TRPCError } from "@trpc/server";
5	import { z } from "zod";
6	
7	/**
8	 * (MULTI-REPO WORKSPACE) A multi-repo project groups N independent git
9	 * repositories under one sidebar row. Creating a workspace on it fans out the
10	 * SAME branch name as a `git worktree add` in every member repo, gathered
11	 * under one container folder that opens as a plain (non-git) workspace.
12	 *
13	 * The member list CANNOT live in the cloud (the fork can't migrate the cloud
14	 * schema) or the host-service SQLite (avoids a local migration). It lives in a
15	 * declared config file inside the project's ANCHOR directory — a small
16	 * fork-owned folder under ~/.superset/multi-repo/<projectId> that serves as
17	 * the project's `repoPath`. The anchor is a plain directory (never a git
18	 * repo), so every existing non-git guard applies to the project untouched.
19	 */
20	export const MULTI_REPO_CONFIG_FILENAME = "superset-multi-repo.json";
21	
22	export const MULTI_REPO_ANCHORS_DIR = join(
23		homedir(),
24		".superset",
25		"multi-repo",
26	);
27	
28	const multiRepoConfigSchema = z.object({
29		version: z.literal(1),
30		name: z.string().min(1),
31		/** Canonical git roots of the member repositories (>=2, unique basenames). */
32		memberRepoPaths: z.array(z.string().min(1)).min(2),
33	});
34	
35	export type MultiRepoConfig = z.infer<typeof multiRepoConfigSchema>;
36	
37	export function multiRepoConfigPath(anchorPath: string): string {
38		return join(anchorPath, MULTI_REPO_CONFIG_FILENAME);
39	}
40	
41	/**
42	 * THE container layout convention: member repo `<x>/foo` lives at
43	 * `<container>/foo` inside every branch workspace. Single source of truth —
44	 * create, inspect, destroy, and project-remove all derive member paths here
45	 * (basename uniqueness in the member list exists to serve this mapping).
46	 */
47	export function memberWorktreePath(
48		containerPath: string,
49		memberRepoPath: string,
50	): string {
51		return join(containerPath, basename(memberRepoPath));
52	}
53	
54	// Hoisted: readMultiRepoConfig runs on every workspaces.create/destroy/inspect
55	// and once per project in the boot sweep; the anchors root never changes.
56	const ANCHOR_ROOT_LOWER = resolve(MULTI_REPO_ANCHORS_DIR).toLowerCase();
57	
58	/** True when `repoPath` sits inside the fork-owned multi-repo anchors dir. */
59	function isMultiRepoAnchorPath(repoPath: string): boolean {
60		const resolved = resolve(repoPath).toLowerCase();
61		return (
62			resolved.startsWith(ANCHOR_ROOT_LOWER + "\\") ||
63			resolved.startsWith(ANCHOR_ROOT_LOWER + "/")
64		);
65	}
66	
67	/**
68	 * Read + validate the multi-repo config for a project `repoPath`.
69	 *
70	 * Multi-repo identity is the fork-owned ANCHOR DIRECTORY, never the config
71	 * file's presence alone: an ordinary repo that happens to contain a file
72	 * named `superset-multi-repo.json` (committed by another user of this fork,
73	 * copied, etc.) must NOT flip into multi-repo semantics — that would skip
74	 * its real worktree-remove path and rmSync a live worktree on delete.
75	 *
76	 * - Not an anchor path -> `null`, unconditionally (ordinary project).
77	 * - Anchor path with a valid config -> the config.
78	 * - Anchor path with a missing/unreadable/invalid config -> throws loud:
79	 *   silently demoting the project to a plain folder would make its "+"
80	 *   mint workspaces with no worktrees.
81	 */
82	export function readMultiRepoConfig(repoPath: string): MultiRepoConfig | null {
83		if (!isMultiRepoAnchorPath(repoPath)) return null;
84		const configPath = multiRepoConfigPath(repoPath);
85		if (!existsSync(configPath)) {
86			throw new TRPCError({
87				code: "INTERNAL_SERVER_ERROR",
88				message: `Multi-repo member list missing at ${configPath}. Restore the file (version 1, name, memberRepoPaths) or delete the project.`,
89			});
90		}
91		let raw: string;
92		try {
93			raw = readFileSync(configPath, "utf8");
94		} catch (err) {
95			throw new TRPCError({
96				code: "INTERNAL_SERVER_ERROR",
97				message: `Could not read multi-repo config at ${configPath}: ${
98					err instanceof Error ? err.message : String(err)
99				}`,
100			});
101		}
102		let parsed: unknown;
103		try {
104			parsed = JSON.parse(raw);
105		} catch {
106			throw new TRPCError({
107				code: "INTERNAL_SERVER_ERROR",
108				message: `Multi-repo config at ${configPath} is not valid JSON. Fix or remove the file.`,
109			});
110		}
111		const result = multiRepoConfigSchema.safeParse(parsed);
112		if (!result.success) {
113			throw new TRPCError({
114				code: "INTERNAL_SERVER_ERROR",
115				message: `Multi-repo config at ${configPath} is invalid: ${result.error.message}`,
116			});
117		}
118		return result.data;
119	}
120

