1	import { existsSync, rmSync } from "node:fs";
2	import { basename } from "node:path";
3	import { TRPCError } from "@trpc/server";
4	import {
5		memberWorktreePath,
6		type MultiRepoConfig,
7	} from "../../../runtime/git/multi-repo";
8	import type { HostServiceContext } from "../../../types";
9	import { normalizeWorktreePath } from "../workspace-creation/shared/worktree-list";
10	
11	/**
12	 * (MULTI-REPO WORKSPACE) Cleanup fan-out for multi-repo branch workspaces:
13	 * the workspace's worktreePath is a CONTAINER folder holding one worktree per
14	 * member repo, so inspect/destroy/project-remove walk the members. Fork-owned
15	 * module — upstream's workspace-cleanup.ts and project.ts keep only
16	 * `if (multiRepo)` dispatch shims, so nightly merges never see these bodies
17	 * inside a conflict region.
18	 */
19	
20	type GitClient = Awaited<ReturnType<HostServiceContext["git"]>>;
21	
22	/** Dirty/unpushed probe shared by inspect + preflight (one definition). */
23	async function probeGitState(
24		git: GitClient,
25	): Promise<{ hasChanges: boolean; hasUnpushedCommits: boolean }> {
26		const status = await git.status();
27		let hasUnpushedCommits = false;
28		try {
29			const result = await git.raw([
30				"rev-list",
31				"--count",
32				"HEAD",
33				"--not",
34				"--remotes",
35			]);
36			const count = Number.parseInt(result.trim(), 10);
37			hasUnpushedCommits = Number.isFinite(count) && count > 0;
38		} catch {
39			// rev-list failure isn't a signal we can act on.
40		}
41		return { hasChanges: !status.isClean(), hasUnpushedCommits };
42	}
43	
44	/**
45	 * Delete-dialog preview: aggregate dirty/unpushed across all member worktrees.
46	 * The container itself is non-git, so the single-path probe would report
47	 * "clean" for a workspace whose MEMBER worktrees are dirty — and the dialog's
48	 * silent force-retry would then drop those changes without ever warning.
49	 * Members are independent repos; probed in parallel (dialog-open latency).
50	 */
51	export async function inspectMultiRepoWorkspace(
52		ctx: HostServiceContext,
53		config: MultiRepoConfig,
54		containerPath: string,
55	): Promise<{ hasChanges: boolean; hasUnpushedCommits: boolean }> {
56		const states = await Promise.all(
57			config.memberRepoPaths.map(async (memberRepoPath) => {
58				const subPath = memberWorktreePath(containerPath, memberRepoPath);
59				if (!existsSync(subPath)) return null;
60				try {
61					return await probeGitState(await ctx.git(subPath));
62				} catch {
63					// Unreadable member — destroy handles it; nothing to warn on.
64					return null;
65				}
66			}),
67		);
68		return {
69			hasChanges: states.some((s) => s?.hasChanges),
70			hasUnpushedCommits: states.some((s) => s?.hasUnpushedCommits),
71		};
72	}
73	
74	/** Destroy preflight: throw CONFLICT on the first dirty member worktree. */
75	export async function preflightMultiRepoDirtyCheck(
76		ctx: HostServiceContext,
77		config: MultiRepoConfig,
78		containerPath: string,
79	): Promise<void> {
80		for (const memberRepoPath of config.memberRepoPaths) {
81			const subPath = memberWorktreePath(containerPath, memberRepoPath);
82			if (!existsSync(subPath)) continue;
83			try {
84				const { hasChanges } = await probeGitState(await ctx.git(subPath));
85				if (hasChanges) {
86					throw new TRPCError({
87						code: "CONFLICT",
88						message: `Worktree has uncommitted changes (${basename(memberRepoPath)})`,
89					});
90				}
91			} catch (err) {
92				if (err instanceof TRPCError) throw err;
93				// Unreadable member — handled best-effort by the cleanup phase.
94			}
95		}
96	}
97	
98	/**
99	 * Destroy step 2b for multi-repo: remove each member's worktree (verified
100	 * against git's registry, mirroring the single-repo path's semantics), then
101	 * the container. Mutates `warnings`; returns the opened member gits (for the
102	 * later branch-delete step) — a member that could not be opened is absent.
103	 *
104	 * Decoupling rules per member match single-repo: an unopenable repo whose
105	 * sub-worktree is already gone warns-and-skips; an unopenable repo whose
106	 * sub-worktree EXISTS fails loud (the container rmSync would otherwise tear
107	 * it down unverified); a locked worktree warns, is pruned from git's
108	 * registry, and forces the container to stay on disk.
109	 */
110	export async function destroyMultiRepoWorktrees(
111		ctx: HostServiceContext,
112		config: MultiRepoConfig,
113		containerPath: string,
114		warnings: string[],
115	): Promise<Array<{ repoPath: string; git: GitClient }>> {
116		const memberGits: Array<{ repoPath: string; git: GitClient }> = [];
117		let leaveContainerOnDisk = false;
118	
119		for (const memberRepoPath of config.memberRepoPaths) {
120			const subPath = memberWorktreePath(containerPath, memberRepoPath);
121			let memberGit: GitClient;
122			try {
123				memberGit = await ctx.git(memberRepoPath);
124			} catch (err) {
125				const message = err instanceof Error ? err.message : String(err);
126				if (existsSync(subPath)) {
127					throw new TRPCError({
128						code: "INTERNAL_SERVER_ERROR",
129						message: `Cannot open member repo at ${memberRepoPath} while its worktree still exists: ${message}`,
130					});
131				}
132				warnings.push(
133					`Failed to open member repo at ${memberRepoPath}: ${message}`,
134				);
135				continue;
136			}
137			memberGits.push({ repoPath: memberRepoPath, git: memberGit });
138	
139			const canonicalPath = normalizeWorktreePath(subPath);
140			await memberGit
141				.raw(["worktree", "remove", "--force", "--force", canonicalPath])
142				.catch(() => {});
143	
144			let stillRegistered = true;
145			try {
146				stillRegistered = await isMemberWorktreeRegistered(memberGit, subPath);
147			} catch (err) {
148				const message = err instanceof Error ? err.message : String(err);
149				if (!existsSync(subPath)) {
150					stillRegistered = false;
151				} else {
152					warnings.push(
153						`Failed to remove worktree at ${subPath}: ${message}. It may be locked by another process (editor/terminal); the workspace was deleted and the folder left on disk.`,
154					);
155					try {
156						await memberGit.raw(["worktree", "prune"]);
157					} catch {}
158					stillRegistered = false;
159					// We just promised this folder stays on disk — the container
160					// rmSync below must not delete it out from under the lock.
161					leaveContainerOnDisk = true;
162				}
163			}
164			if (stillRegistered) {
165				// This member's git still tracks a live worktree — removal genuinely
166				// failed. Keep the cloud row so the workspace stays visible and
167				// retryable.
168				throw new TRPCError({
169					code: "INTERNAL_SERVER_ERROR",
170					message: `Failed to remove worktree at ${subPath}`,
171				});
172			}
173		}
174	
175		// Container folder: leftovers (untracked files the user dropped at the
176		// container root) go with the workspace, same as a single worktree dir —
177		// unless a locked member worktree was left inside it.
178		if (leaveContainerOnDisk) {
179			warnings.push(
180				`Container folder left on disk at ${containerPath} (a member worktree could not be removed).`,
181			);
182		} else {
183			try {
184				rmSync(containerPath, { recursive: true, force: true });
185			} catch (err) {
186				const message = err instanceof Error ? err.message : String(err);
187				warnings.push(
188					`Failed to remove container folder at ${containerPath}: ${message}`,
189				);
190			}
191		}
192		return memberGits;
193	}
194	
195	// Same registry check as workspace-cleanup's isRegisteredWorktree, local to
196	// this module so the upstream file needs no export churn: reads git's own
197	// worktree list (realpath-canonicalized) rather than parsing remove's output.
198	async function isMemberWorktreeRegistered(
199		git: GitClient,
200		worktreePath: string,
201	): Promise<boolean> {
202		const target = normalizeWorktreePath(worktreePath);
203		const raw = await git.raw(["worktree", "list", "--porcelain"]);
204		return raw
205			.split(/\r?\n/)
206			.filter((line) => line.startsWith("worktree "))
207			.map((line) => line.slice("worktree ".length).trim())
208			.some((path) => normalizeWorktreePath(path) === target);
209	}
210	
211	/**
212	 * Destroy step 4 for multi-repo: delete the shared branch in EVERY member.
213	 * Honest result: true ONLY when every configured member was reachable AND no
214	 * delete failed — an empty/partial member list must not report success.
215	 */
216	export async function deleteMultiRepoBranches(
217		memberGits: Array<{ repoPath: string; git: GitClient }>,
218		totalMemberCount: number,
219		branch: string,
220		warnings: string[],
221	): Promise<boolean> {
222		let memberDeleteFailed = false;
223		for (const member of memberGits) {
224			try {
225				// `branch --list` exits 0 whether or not the branch exists (empty
226				// output when absent) — an absent ref already satisfies the goal.
227				const out = await member.git.raw(["branch", "--list", branch]);
228				if (out.trim().length > 0) {
229					await member.git.raw(["branch", "-D", branch]);
230				}
231			} catch (err) {
232				const message = err instanceof Error ? err.message : String(err);
233				memberDeleteFailed = true;
234				warnings.push(
235					`Failed to delete branch ${branch} in ${member.repoPath}: ${message}`,
236				);
237			}
238		}
239		return !memberDeleteFailed && memberGits.length === totalMemberCount;
240	}
241	
242	/**
243	 * project.remove sweep for multi-repo: best-effort worktree removal per
244	 * member per workspace (mirroring the single-repo sweep's warn-and-continue
245	 * policy), then each container, then the fork-owned anchor dir itself.
246	 * Member git clients are resolved ONCE per member, not per workspace.
247	 */
248	export async function removeMultiRepoProjectArtifacts(
249		ctx: HostServiceContext,
250		config: MultiRepoConfig,
251		anchorPath: string,
252		workspaceWorktreePaths: string[],
253	): Promise<void> {
254		const memberGits = new Map<string, GitClient>();
255		for (const memberRepoPath of config.memberRepoPaths) {
256			try {
257				memberGits.set(memberRepoPath, await ctx.git(memberRepoPath));
258			} catch (err) {
259				console.warn("[project.remove] failed to open member repo", {
260					memberRepoPath,
261					err,
262				});
263			}
264		}
265	
266		for (const containerPath of workspaceWorktreePaths) {
267			for (const [memberRepoPath, git] of memberGits) {
268				const subPath = memberWorktreePath(containerPath, memberRepoPath);
269				try {
270					await git.raw(["worktree", "remove", "--force", subPath]);
271				} catch (err) {
272					console.warn("[project.remove] failed to remove member worktree", {
273						worktreePath: subPath,
274						err,
275					});
276				}
277			}
278			try {
279				rmSync(containerPath, { recursive: true, force: true });
280			} catch (err) {
