25	interface V2ProjectSettingsProps {
26		projectId: string;
27		hostId: string | null;
28	}
29	
30	export function V2ProjectSettings({
31		projectId,
32		hostId,
33	}: V2ProjectSettingsProps) {
34		const navigate = useNavigate();
35		const collections = useCollections();
36		const { machineId } = useLocalHostService();
37		const { currentDeviceName, localHostId, otherHosts } =
38			useWorkspaceHostOptions();
39		const targetHostUrl = useHostUrl(hostId);
40		const targetHostId = hostId ?? machineId;
41	
42		const { data: v2Project, isReady } = useLiveQuery(
43			(q) =>
44				q
45					.from({ projects: collections.v2Projects })
46					.where(({ projects }) => eq(projects.id, projectId))
47					.select(({ projects }) => ({ ...projects })),
48			[collections, projectId],
49		);
50	
51		const hostOptions = useMemo<HostSelectOption[]>(() => {
52			const options: HostSelectOption[] = [];
53			if (localHostId) {
54				options.push({
55					id: localHostId,
56					name: currentDeviceName ?? "This device",
57					isLocal: true,
58					isOnline: true,
59				});
60			}
61			for (const host of otherHosts) {
62				options.push({
63					id: host.id,
64					name: host.name,
65					isLocal: false,
66					isOnline: host.isOnline,
67				});
68			}
69			if (targetHostId && !options.some((option) => option.id === targetHostId)) {
70				options.push({
71					id: targetHostId,
72					name: targetHostId === machineId ? "This device" : targetHostId,
73					isLocal: targetHostId === machineId,
74					isOnline: targetHostId === machineId,
75				});
76			}
77			return options;
78		}, [currentDeviceName, localHostId, machineId, otherHosts, targetHostId]);
79	
80		const selectedHost = useMemo(
81			() => hostOptions.find((option) => option.id === targetHostId) ?? null,
82			[hostOptions, targetHostId],
83		);
84		const targetHostName = useMemo(() => {
85			if (selectedHost?.name) return selectedHost.name;
86			if (!targetHostId || targetHostId === machineId) return "this device";
87			return targetHostId;
88		}, [machineId, selectedHost, targetHostId]);
89		const hasMultipleHosts = hostOptions.length > 1;
90		const isRemoteTarget = Boolean(
91			targetHostId && machineId && targetHostId !== machineId,
92		);
93	
94		const { data: hostProject, refetch: refetchHostProject } = useQuery({
95			queryKey: ["host-project", "get", targetHostUrl, projectId],
96			enabled: !!targetHostUrl,
97			queryFn: async () => {
98				if (!targetHostUrl) return null;
99				const client = getHostServiceClientByUrl(targetHostUrl);
100				return client.project.get.query({ projectId });
101			},
102		});
103	
104		const project = v2Project?.[0];
105		if (!project) {
106			if (!isReady) return null;
107			return (
108				<div className="p-6 text-sm text-muted-foreground select-text cursor-text">
109					Project not found.
110				</div>
111			);
112		}
113	
114		return (
115			<div className="p-6 max-w-4xl w-full mx-auto select-text">
116				<header className="mb-8 flex items-center justify-between gap-4">
