13	import { useState } from "react";
14	import { LuFolderPlus, LuLoaderCircle, LuX } from "react-icons/lu";
15	import { electronTrpc } from "renderer/lib/electron-trpc";
16	import { getHostServiceClientByUrl } from "renderer/lib/host-service-client";
17	import { showHostServiceUnavailableToast } from "renderer/lib/host-service-unavailable";
18	import { useFinalizeProjectSetup } from "renderer/react-query/projects";
19	import { getPathBaseName } from "shared/absolute-paths";
20	import { useLocalHostService } from "renderer/routes/_authenticated/providers/LocalHostServiceProvider";
21	
22	interface MultiFolderProjectModalProps {
23		open: boolean;
24		onOpenChange: (open: boolean) => void;
25		onSuccess?: (result: { projectId: string }) => void;
26		onError?: (message: string) => void;
27	}
28	
29	/**
30	 * (MULTI-REPO WORKSPACE) "Open from multi-folder": pick N folders (each must
31	 * be a git repo — validated on add via project.probePath), name the group,
32	 * and create a multi-repo project. Its "+" then fans the same branch name out
33	 * as a worktree in every member repo.
34	 */
35	export function MultiFolderProjectModal({
36		open,
37		onOpenChange,
38		onSuccess,
39		onError,
40	}: MultiFolderProjectModalProps) {
41		const hostService = useLocalHostService();
42		const { activeHostUrl } = hostService;
43		const finalizeSetup = useFinalizeProjectSetup();
44		const selectDirectories = electronTrpc.window.selectDirectories.useMutation();
45	
46		const [name, setName] = useState("");
47		const [repoPaths, setRepoPaths] = useState<string[]>([]);
48		const [working, setWorking] = useState(false);
49	
50		const reset = () => {
51			setName("");
52			setRepoPaths([]);
53			setWorking(false);
54		};
55	
56		const handleOpenChange = (next: boolean) => {
57			if (!next && working) return;
58			if (!next) reset();
59			onOpenChange(next);
60		};
61	
62		const handleAddFolders = async () => {
63			if (!activeHostUrl) {
64				showHostServiceUnavailableToast(hostService, {
65					action: "validate the selected folders",
66				});
67				return;
68			}
69			try {
70				const result = await selectDirectories.mutateAsync({
71					title: "Select git repositories",
72				});
73				if (result.canceled || result.paths.length === 0) return;
74	
75				const client = getHostServiceClientByUrl(activeHostUrl);
76				const additions: string[] = [];
77				// Probes are independent host round-trips — run them in parallel,
78				// then apply the order-dependent dedup over the resolved results.
79				const probes = await Promise.all(
80					result.paths.map(async (path) => ({
81						path,
82						probe: await client.project.probePath.query({ repoPath: path }),
83					})),
84				);
85				for (const { path, probe } of probes) {
86					// Register the canonical repo ROOT — a picked subfolder of a repo
87					// would otherwise masquerade as a repo of its own. (isGitRepo is
88					// derived from gitRoot server-side; one check suffices.)
89					if (!probe.gitRoot) {
90						toast.error(`Not a git repository: ${path}`, {
91							description:
92								"Every member of a multi-repo workspace must be a git repo.",
93						});
94						continue;
95					}
96					const root = probe.gitRoot;
97					if (repoPaths.includes(root) || additions.includes(root)) continue;
98					// Case-insensitive: Windows paths collide regardless of case.
99					const base = getPathBaseName(root);
100					const clash = [...repoPaths, ...additions].find(
101						(existing) =>
102							getPathBaseName(existing).toLowerCase() === base.toLowerCase(),
103					);
104					if (clash) {
105						toast.error(`Two repositories share the folder name "${base}"`, {
106							description: `${clash} is already selected. Member folder names become the per-repo subfolders of each workspace.`,
107						});
108						continue;
109					}
110					additions.push(root);
