700		 *
701		 *   3. Best-effort `git worktree remove` for each non-main local
702		 *      workspace so subsequent worktree commands aren't confused.
703		 *
704		 * The on-disk repo directory is NEVER auto-removed. The user's code is
705		 * their code; deletion of the working tree must be an explicit action,
706		 * not a side-effect of project removal. Returns repoPath so a future
707		 * UI can offer an explicit "delete files too" follow-up.
708		 */
709		remove: protectedProcedure
710			.input(z.object({ projectId: z.string().uuid() }))
711			.mutation(async ({ ctx, input }) => {
712				await ctx.api.v2Project.delete.mutate({
713					organizationId: ctx.organizationId,
714					id: input.projectId,
715				});
716	
717				const localProject = ctx.db.query.projects
718					.findFirst({ where: eq(projects.id, input.projectId) })
719					.sync();
720	
721				if (!localProject) return { success: true, repoPath: null };
722	
723				const localWorkspaces = ctx.db
724					.select()
725					.from(workspaces)
726					.where(eq(workspaces.projectId, input.projectId))
727					.all();
728	
729				// (MULTI-REPO WORKSPACE) The project repoPath is a non-git anchor;
730				// each workspace's worktreePath is a container of per-member
731				// worktrees. The fork module fans the removal out per member
732				// (best-effort, like the single-repo loop below), drops each
733				// container, and removes the fork-owned anchor dir itself after
734				// the rows are gone. Member repos are never touched.
735				let multiRepoConfig: ReturnType<typeof readMultiRepoConfig> = null;
736				try {
737					multiRepoConfig = readMultiRepoConfig(localProject.repoPath);
738				} catch (err) {
739					console.warn("[project.remove] unreadable multi-repo config", {
740						projectId: input.projectId,
741						err,
742					});
743				}
744				if (multiRepoConfig) {
745					await removeMultiRepoProjectArtifacts(
746						ctx,
747						multiRepoConfig,
748						localProject.repoPath,
749						localWorkspaces.map((ws) => ws.worktreePath),
750					);
751				} else {
752					for (const ws of localWorkspaces) {
753						if (ws.worktreePath === localProject.repoPath) continue;
754						try {
755							const git = await ctx.git(localProject.repoPath);
756							await git.raw(["worktree", "remove", ws.worktreePath]);
757						} catch (err) {
758							console.warn("[project.remove] failed to remove worktree", {
759								projectId: input.projectId,
760								worktreePath: ws.worktreePath,
761								err,
762							});
763						}
764					}
765				}
766	
767				try {
768					// Per-row so each deletion broadcasts; the cloud project delete
769					// above already cascaded the cloud rows, so no tombstones.
770					for (const ws of localWorkspaces) {
771						deleteLocalWorkspace({ db: ctx.db, eventBus: ctx.eventBus }, ws.id, {
772							queueCloudDelete: false,
773						});
774					}
775					ctx.db.delete(projects).where(eq(projects.id, input.projectId)).run();
776				} catch (err) {
777					console.warn("[project.remove] failed to delete local rows", {
778						projectId: input.projectId,
779						err,
780					});
781				}
782	
783				return { success: true, repoPath: localProject.repoPath };
784			}),
785	});
