24		prunable: { reason: string } | null;
25	};
26	
27	export function parseWorktreeList(raw: string): WorktreeRecord[] {
28		const records: WorktreeRecord[] = [];
29		let current: WorktreeRecord | null = null;
30		const flush = () => {
31			if (current) {
32				records.push(current);
33				current = null;
34			}
35		};
36		for (const line of raw.split("\n")) {
37			if (line.startsWith("worktree ")) {
38				flush();
39				current = {
40					path: line.slice("worktree ".length).trim(),
41					head: null,
42					branch: null,
43					detached: false,
44					bare: false,
45					locked: null,
46					prunable: null,
47				};
48			} else if (!current) {
49				// Stray line before the first `worktree` block — ignore.
50			} else if (line.startsWith("HEAD ")) {
51				current.head = line.slice("HEAD ".length).trim() || null;
52			} else if (line.startsWith("branch ")) {
53				const ref = line.slice("branch ".length).trim();
54				current.branch = ref.startsWith("refs/heads/")
55					? ref.slice("refs/heads/".length)
56					: ref;
57			} else if (line === "detached") {
58				current.detached = true;
59			} else if (line === "bare") {
60				current.bare = true;
61			} else if (line === "locked" || line.startsWith("locked ")) {
62				current.locked = { reason: line.slice("locked".length).trim() };
63			} else if (line === "prunable" || line.startsWith("prunable ")) {
64				current.prunable = { reason: line.slice("prunable".length).trim() };
65			} else if (line === "") {
66				flush();
67			}
68		}
