+					if (!open && !working) setPendingRemove(null);
+				}}
+			>
+				<AlertDialogContent>
+					<AlertDialogHeader>
+						<AlertDialogTitle>
+							Remove "{pendingRemove ? getPathBaseName(pendingRemove) : ""}"?
+						</AlertDialogTitle>
+						<AlertDialogDescription>
