+						<AlertDialogCancel disabled={working}>Cancel</AlertDialogCancel>
+						<AlertDialogAction
+							onClick={(e) => {
+								e.preventDefault();
+								void handleRemove();
+							}}
+							disabled={working}
+							className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
+						>
